import React, { useState, useCallback } from 'react';

const MapPicker = ({ onLocationSelect, initialLat = 27.7172, initialLng = 85.3240 }) => {
  const [selectedLocation, setSelectedLocation] = useState({
    lat: initialLat,
    lng: initialLng
  });

  const handleMapClick = useCallback((event) => {
    const lat = event.latLng.lat();
    const lng = event.latLng.lng();

    setSelectedLocation({ lat, lng });
    onLocationSelect(lat, lng);
  }, [onLocationSelect]);

  // Simple map implementation without Google Maps API
  const handleCoordinateInput = (lat, lng) => {
    if (lat && lng) {
      setSelectedLocation({ lat: parseFloat(lat), lng: parseFloat(lng) });
      onLocationSelect(parseFloat(lat), parseFloat(lng));
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.mapPlaceholder}>
        <h4>Location Picker</h4>
        <p>Click on the coordinate inputs below to set location</p>
        <div style={styles.coordinates}>
          <div style={styles.coordInput}>
            <label>Latitude:</label>
            <input
              type="number"
              step="any"
              value={selectedLocation.lat}
              onChange={(e) => handleCoordinateInput(e.target.value, selectedLocation.lng)}
              style={styles.input}
            />
          </div>
          <div style={styles.coordInput}>
            <label>Longitude:</label>
            <input
              type="number"
              step="any"
              value={selectedLocation.lng}
              onChange={(e) => handleCoordinateInput(selectedLocation.lat, e.target.value)}
              style={styles.input}
            />
          </div>
        </div>

        <div style={styles.presetLocations}>
          <h5>Quick Select:</h5>
          <button 
            onClick={() => handleCoordinateInput(27.7172, 85.3240)}
            style={styles.presetBtn}
          >
            Kathmandu Center
          </button>
          <button 
            onClick={() => handleCoordinateInput(28.2096, 83.9856)}
            style={styles.presetBtn}
          >
            Pokhara Lakeside
          </button>
          <button 
            onClick={() => handleCoordinateInput(26.4525, 87.2718)}
            style={styles.presetBtn}
          >
            Biratnagar Center
          </button>
        </div>
      </div>
    </div>
  );
};

const styles = {
  container: {
    marginBottom: '1rem'
  },
  mapPlaceholder: {
    border: '2px dashed #d1d5db',
    borderRadius: '8px',
    padding: '2rem',
    textAlign: 'center',
    backgroundColor: '#f9fafb',
    minHeight: '300px'
  },
  coordinates: {
    display: 'flex',
    gap: '1rem',
    justifyContent: 'center',
    margin: '1rem 0'
  },
  coordInput: {
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center'
  },
  input: {
    padding: '0.5rem',
    border: '1px solid #d1d5db',
    borderRadius: '4px',
    width: '120px',
    marginTop: '0.5rem'
  },
  presetLocations: {
    marginTop: '1.5rem'
  },
  presetBtn: {
    backgroundColor: '#3b82f6',
    color: 'white',
    border: 'none',
    padding: '0.5rem 1rem',
    borderRadius: '4px',
    margin: '0 0.5rem',
    cursor: 'pointer',
    fontSize: '0.9rem'
  }
};

export default MapPicker;
